public static boolean solve(long[] nums) {
    int n = nums.length;
    if (n < 3) return false;

    // Find the peak index p
    int p = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            p = i - 1;
            break;
        }
    }

    // Find the valley index q
    int q = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            q = i - 1;
            break;
        }
    }

    // Check if p and q are valid
    if (p == 0 || q == 0 || p == q) {
        return false;
    }

    // Check if the array is strictly increasing up to p
    for (int i = 1; i <= p; i++) {
        if (nums[i] <= nums[i - 1]) {
            return false;
        }
    }

    // Check if the array is strictly decreasing from p to q
    for (int i = p; i > q; i--) {
        if (nums[i] <= nums[i - 1]) {
            return false;
        }
    }

    // Check if the array is strictly increasing from q to end
    for (int i = q + 1; i < n; i++) {
        if (nums[i] <= nums[i - 1]) {
            return false;
        }
    }

    return true;
}
